using System.Collections.Generic;
using UnityEngine;

namespace Darkroom
{
    /// Procedural pixel art — sprites authored as string maps, world tiles
    /// generated by rule. Still zero external assets.
    public static class PixelArt
    {
        /// rows are listed top to bottom; '.' = transparent.
        public static Sprite FromMap(string name, string[] rows, Dictionary<char, Color32> palette, float ppu)
        {
            int h = rows.Length, w = rows[0].Length;
            var tex = new Texture2D(w, h, TextureFormat.RGBA32, false);
            tex.filterMode = FilterMode.Bilinear;
            var px = new Color32[w * h];
            for (int y = 0; y < h; y++)
                for (int x = 0; x < w; x++)
                {
                    char c = rows[y][x];
                    px[(h - 1 - y) * w + x] = c == '.' ? new Color32(0, 0, 0, 0) : palette[c];
                }
            tex.SetPixels32(px);
            tex.Apply();
            var s = Sprite.Create(tex, new Rect(0, 0, w, h), new Vector2(0.5f, 0.5f), ppu, 0, SpriteMeshType.FullRect);
            s.name = name;
            return s;
        }

        static Sprite MakeTile(string name, int size, float ppu, System.Func<int, int, Color32> pixel)
        {
            var tex = new Texture2D(size, size, TextureFormat.RGBA32, false);
            tex.filterMode = FilterMode.Bilinear;
            tex.wrapMode = TextureWrapMode.Repeat;
            var px = new Color32[size * size];
            for (int y = 0; y < size; y++)
                for (int x = 0; x < size; x++)
                    px[y * size + x] = pixel(x, y);
            tex.SetPixels32(px);
            tex.Apply();
            var s = Sprite.Create(tex, new Rect(0, 0, size, size), new Vector2(0.5f, 0.5f), ppu, 0, SpriteMeshType.FullRect);
            s.name = name;
            return s;
        }

        static Color32 C(int rgb) =>
            new Color32((byte)((rgb >> 16) & 0xFF), (byte)((rgb >> 8) & 0xFF), (byte)(rgb & 0xFF), 255);

        // ---------- noise ----------

        internal static float Hash(int x, int y, int s)
        {
            unchecked
            {
                int h = x * 374761393 + y * 668265263 + s * 1442695041;
                h = (h ^ (h >> 13)) * 1274126177;
                return ((h ^ (h >> 16)) & 0x7FFFFFFF) / (float)int.MaxValue;
            }
        }

        internal static float ValueNoise(float x, float y, int seed)
        {
            int x0 = Mathf.FloorToInt(x), y0 = Mathf.FloorToInt(y);
            float fx = x - x0, fy = y - y0;
            float a = Hash(x0, y0, seed), b = Hash(x0 + 1, y0, seed);
            float c = Hash(x0, y0 + 1, seed), d = Hash(x0 + 1, y0 + 1, seed);
            return Mathf.Lerp(Mathf.Lerp(a, b, fx), Mathf.Lerp(c, d, fx), fy);
        }

        // ---------- world tiles ----------

        static Sprite _ground, _darkPath, _barrier, _door;
        static Sprite _concrete, _wall, _lightCone, _coneShade;

        /// Photo/illustration texture from StreamingAssets (CC0/authored, see README credits).
        /// Returns null when the file is missing — callers fall back to procedural.
        static Sprite LoadExternal(string file, float ppu) => LoadExternal(file, ppu, new Vector2(0.5f, 0.5f));

        /// Public single-art loader for one-off props (e.g. the prologue safelight
        /// fixture). StreamingAssets-relative path; null if absent (caller falls back).
        public static Sprite Art(string file, float ppu) => LoadExternal(file, ppu);

        static Sprite LoadExternal(string file, float ppu, Vector2 pivot)
        {
            try
            {
                string p = System.IO.Path.Combine(Application.streamingAssetsPath, file);
                if (!System.IO.File.Exists(p)) return null;
                var tex = new Texture2D(2, 2, TextureFormat.RGBA32, false);
                if (!tex.LoadImage(System.IO.File.ReadAllBytes(p))) return null;
                tex.wrapMode = TextureWrapMode.Repeat; // tiled walls need it; moot for feathered scenes/cutouts
                tex.filterMode = FilterMode.Bilinear;
                var s = Sprite.Create(tex, new Rect(0, 0, tex.width, tex.height),
                    pivot, ppu, 0, SpriteMeshType.FullRect);
                s.name = file;
                return s;
            }
            catch { return null; }
        }

        /// Try each StreamingAssets-relative file in order; first that loads wins.
        /// Lets authored/AI art (art/…) override the legacy photo, which overrides procedural.
        static Sprite LoadExternalFirst(float ppu, params string[] files)
        {
            foreach (var f in files) { var s = LoadExternal(f, ppu); if (s != null) return s; }
            return null;
        }

        /// Concrete: cool dark authored wall (art/wall_concrete.png), legacy photo,
        /// then procedural noise. 512 ppu => one 1K tile spans 2 units.
        public static Sprite ConcreteTile
        {
            get
            {
                if (_concrete == null) _concrete = LoadExternalFirst(512f, "art/wall_concrete.png", "concrete.jpg");
                if (_concrete == null)
                    _concrete = MakeTile("ConcreteTile", 64, 64f, (x, y) =>
                    {
                        float n = ValueNoise(x / 8f, y / 8f, 11) * 0.6f + ValueNoise(x / 3f, y / 3f, 23) * 0.4f;
                        float v = 0.30f + n * 0.14f;
                        if (ValueNoise(x / 16f, y / 5f, 37) > 0.88f) v *= 0.7f; // grime streaks
                        byte g = (byte)(v * 255f);
                        return new Color32(g, g, (byte)Mathf.Min(255, g + 8), 255);
                    });
                return _concrete;
            }
        }

        /// Wall: cool dark plaster (art/wall_plaster.png). Replaces the old red-brick
        /// photo, which clashed with the monochrome darkroom palette. Legacy photo +
        /// neutral-grey procedural fallback kept so the game always renders.
        public static Sprite WallTile
        {
            get
            {
                if (_wall == null) _wall = LoadExternalFirst(512f, "art/wall_plaster.png", "bricks.jpg");
                if (_wall == null)
                    _wall = MakeTile("WallTile", 64, 64f, (x, y) =>
                    {
                        // neutral-grey ashlar fallback (no red): subtle blocks + speckle
                        int row = y / 16;
                        int xo = (row % 2) * 16;
                        bool mortar = (y % 16) < 2 || ((x + xo) % 32) < 2;
                        if (mortar) return new Color32(0x18, 0x18, 0x1C, 255);
                        float n = ValueNoise(x / 5f, y / 5f, 51);
                        byte g = (byte)((0.22f + n * 0.08f) * 255f);
                        return new Color32(g, g, (byte)Mathf.Min(255, g + 6), 255);
                    });
                return _wall;
            }
        }

        /// Authored/AI illustrated backdrop scenes — every `art/bd_*.png` in
        /// StreamingAssets, loaded at `ppu` (cached). Empty list when none exist, so
        /// the backdrop builder degrades gracefully. Drop a new bd_*.png in and it
        /// is picked up automatically on the next level build — no code change.
        static List<Sprite> _scenes;
        public static List<Sprite> BackdropScenes(float ppu)
        {
            if (_scenes != null) return _scenes;
            _scenes = new List<Sprite>();
            try
            {
                string dir = System.IO.Path.Combine(Application.streamingAssetsPath, "art");
                if (System.IO.Directory.Exists(dir))
                {
                    var files = System.IO.Directory.GetFiles(dir, "bd_*.png");
                    System.Array.Sort(files); // deterministic order
                    foreach (var f in files)
                    {
                        var s = LoadExternal("art/" + System.IO.Path.GetFileName(f), ppu);
                        if (s != null) _scenes.Add(s);
                    }
                }
            }
            catch { /* StreamingAssets not a real dir on some platforms — fall back to none */ }
            return _scenes;
        }

        /// Illustrated mid-ground clutter cutouts — every `art/mid_*.png`, loaded at `ppu`
        /// with a TOP-centre pivot so the builder can hang them from the ceiling band.
        /// Transparent PNGs (chroma-keyed + darkened). Empty list when none exist, so the
        /// builder falls back to its code-drawn silhouettes. Drop a new mid_*.png in and
        /// it is picked up on the next level build — no code change.
        static List<Sprite> _midClutter;
        public static List<Sprite> MidgroundClutter(float ppu)
        {
            if (_midClutter != null) return _midClutter;
            _midClutter = new List<Sprite>();
            try
            {
                string dir = System.IO.Path.Combine(Application.streamingAssetsPath, "art");
                if (System.IO.Directory.Exists(dir))
                {
                    var files = System.IO.Directory.GetFiles(dir, "mid_*.png");
                    System.Array.Sort(files);
                    foreach (var f in files)
                    {
                        var s = LoadExternal("art/" + System.IO.Path.GetFileName(f), ppu, new Vector2(0.5f, 1f));
                        if (s != null) _midClutter.Add(s);
                    }
                }
            }
            catch { /* fall back to code silhouettes */ }
            return _midClutter;
        }

        /// Backdrop-NEAR cutouts — every `art/bn_*.png`, a closer illustrated band that
        /// sits between the far hero scenes and the hanging clutter for layered depth.
        /// Centre pivot (edge-feathered like the far scenes). Empty list when none exist,
        /// so BackdropBuilder.BuildNear falls back to re-using the far scenes scaled down.
        static List<Sprite> _near;
        public static List<Sprite> BackdropNear(float ppu)
        {
            if (_near != null) return _near;
            _near = GlobArt("bn_*.png", ppu, new Vector2(0.5f, 0.5f));
            return _near;
        }

        /// Out-of-focus FOREGROUND cutouts — every `art/fg_*.png`, near-black framing that
        /// sits IN FRONT of the play space (drooping cables, a print edge, an enlarger arm).
        /// Centre pivot. Empty list when none exist, so BackdropBuilder.BuildForeground falls
        /// back to its code-drawn silhouettes. Drop a new fg_*.png in and it auto-loads.
        static List<Sprite> _fg;
        public static List<Sprite> ForegroundCutouts(float ppu)
        {
            if (_fg != null) return _fg;
            _fg = GlobArt("fg_*.png", ppu, new Vector2(0.5f, 0.5f));
            return _fg;
        }

        /// A single silhouette FIGURE cutout for `kind` -> `art/char_<kind>.png` (e.g.
        /// char_worker.png), a faceless dark silhouette per the art bible. BOTTOM-centre
        /// pivot (0.5, 0) so the figure stands on its feet line. Returns null (cached, so we
        /// don't re-stat every build) when absent — BackdropFigures then falls back to the
        /// procedural puppet. Lets a dropped-in PNG stand in for the full SpriteSkin rig
        /// with no code change (rig prefab > char_*.png cutout > code puppet).
        static readonly Dictionary<string, Sprite> _figCache = new Dictionary<string, Sprite>();
        public static Sprite FigureCutout(string kind, float ppu)
        {
            string key = kind.ToLowerInvariant();
            if (_figCache.TryGetValue(key, out var cached)) return cached;
            var s = LoadExternal("art/char_" + key + ".png", ppu, new Vector2(0.5f, 0f));
            _figCache[key] = s;
            return s;
        }

        /// Shared StreamingAssets/art glob loader: every file matching `pattern`, sorted for
        /// deterministic order, loaded at `ppu` with `pivot`. Caches nothing itself (callers
        /// hold the cached list); empty list on any failure so callers degrade gracefully.
        static List<Sprite> GlobArt(string pattern, float ppu, Vector2 pivot)
        {
            var list = new List<Sprite>();
            try
            {
                string dir = System.IO.Path.Combine(Application.streamingAssetsPath, "art");
                if (System.IO.Directory.Exists(dir))
                {
                    var files = System.IO.Directory.GetFiles(dir, pattern);
                    System.Array.Sort(files); // deterministic order
                    foreach (var f in files)
                    {
                        var s = LoadExternal("art/" + System.IO.Path.GetFileName(f), ppu, pivot);
                        if (s != null) list.Add(s);
                    }
                }
            }
            catch { /* StreamingAssets not a real dir on some platforms — fall back to none */ }
            return list;
        }

        /// One 35mm SPROCKET cell — a near-void film base with a soft rounded
        /// perforation — for the diegetic film-gate margins (HUDController.BuildFilmGate).
        /// Stacked down each screen edge so the whole game reads as one frame in the gate.
        static Sprite _sprocket;
        public static Sprite SprocketCell
        {
            get
            {
                if (_sprocket != null) return _sprocket;
                int w = 24, h = 40;
                var tex = new Texture2D(w, h, TextureFormat.RGBA32, false) { filterMode = FilterMode.Bilinear };
                var baseC = new Color32(13, 13, 16, 255);   // film base, near void
                var holeC = new Color32(40, 40, 46, 255);   // soft backlit perforation
                const float rx0 = 5f, rx1 = 18f, ry0 = 9f, ry1 = 30f, rad = 4f;
                var px = new Color32[w * h];
                for (int y = 0; y < h; y++)
                    for (int x = 0; x < w; x++)
                    {
                        bool hole = x >= rx0 && x <= rx1 && y >= ry0 && y <= ry1;
                        if (hole) // round the corners
                        {
                            float cx = Mathf.Clamp(x, rx0 + rad, rx1 - rad);
                            float cy = Mathf.Clamp(y, ry0 + rad, ry1 - rad);
                            if (Mathf.Sqrt((x - cx) * (x - cx) + (y - cy) * (y - cy)) > rad) hole = false;
                        }
                        px[y * w + x] = hole ? holeC : baseC;
                    }
                tex.SetPixels32(px); tex.Apply();
                _sprocket = Sprite.Create(tex, new Rect(0, 0, w, h), new Vector2(0.5f, 0.5f), 24f);
                _sprocket.name = "SprocketCell";
                return _sprocket;
            }
        }

        /// A small hanging photographic PRINT — paper border + a darker photo window with a
        /// wider bottom margin (Polaroid-style). Near-neutral so a checkpoint can tint it cool
        /// (undeveloped negative) then develop it warm on arrival. Used by CheckpointAt.
        static Sprite _printFrame;
        public static Sprite PrintFrame
        {
            get
            {
                if (_printFrame != null) return _printFrame;
                int w = 48, h = 48; // a SQUARE print
                var tex = new Texture2D(w, h, TextureFormat.RGBA32, false) { filterMode = FilterMode.Bilinear };
                var paper = new Color32(235, 234, 226, 255);
                var photo = new Color32(120, 126, 140, 255);
                var px = new Color32[w * h];
                for (int y = 0; y < h; y++)
                    for (int x = 0; x < w; x++)
                    {
                        bool win = x >= 8 && x <= 40 && y >= 13 && y <= 45; // 33x33 square photo, ~13px Polaroid bottom margin
                        px[y * w + x] = win ? photo : paper;
                    }
                tex.SetPixels32(px); tex.Apply();
                _printFrame = Sprite.Create(tex, new Rect(0, 0, w, h), new Vector2(0.5f, 0.5f), 80f);
                _printFrame.name = "PrintFrame";
                return _printFrame;
            }
        }

        /// A soft, irregular, ELONGATED vapor wisp (value-noise modulated, feathered to
        /// nothing at the edges) — for the drifting chemical haze (VaporMotes). Reads as
        /// flowing mist, not a round dust dot.
        static Sprite _vaporWisp;
        public static Sprite VaporWisp
        {
            get
            {
                if (_vaporWisp != null) return _vaporWisp;
                int w = 128, h = 64;
                var tex = new Texture2D(w, h, TextureFormat.RGBA32, false)
                { filterMode = FilterMode.Bilinear, wrapMode = TextureWrapMode.Clamp };
                float cx = w * 0.5f, cy = h * 0.5f, rx = w * 0.5f, ry = h * 0.5f;
                var px = new Color32[w * h];
                for (int y = 0; y < h; y++)
                    for (int x = 0; x < w; x++)
                    {
                        float nx = (x - cx) / rx, ny = (y - cy) / ry;
                        float fall = Mathf.Clamp01(1f - Mathf.Sqrt(nx * nx + ny * ny));
                        fall *= fall; // very soft edge
                        float n = ValueNoise(x / 13f, y / 10f, 7) * 0.6f + ValueNoise(x / 5f, y / 6f, 19) * 0.4f;
                        float a = Mathf.Clamp01(fall * (0.3f + 0.7f * n)); // noise breaks up the blob
                        px[y * w + x] = new Color32(255, 255, 255, (byte)(a * 255f));
                    }
                tex.SetPixels32(px); tex.Apply();
                _vaporWisp = Sprite.Create(tex, new Rect(0, 0, w, h), new Vector2(0.5f, 0.5f), 64f);
                _vaporWisp.name = "VaporWisp";
                return _vaporWisp;
            }
        }

        /// A vertical gradient (opaque at the TOP edge, fading to nothing at the bottom) —
        /// for the HUD's top scrim so the header reads on any background. White; tint via
        /// the Image colour.
        static Sprite _topGrad;
        public static Sprite TopGradient
        {
            get
            {
                if (_topGrad != null) return _topGrad;
                int h = 64;
                var tex = new Texture2D(1, h, TextureFormat.RGBA32, false)
                { filterMode = FilterMode.Bilinear, wrapMode = TextureWrapMode.Clamp };
                var px = new Color32[h];
                for (int y = 0; y < h; y++)
                {
                    float v = y / (float)(h - 1);          // 0 bottom -> 1 top
                    float a = Mathf.SmoothStep(0f, 1f, v); // opaque toward the top
                    px[y] = new Color32(255, 255, 255, (byte)(a * 255f));
                }
                tex.SetPixels32(px); tex.Apply();
                _topGrad = Sprite.Create(tex, new Rect(0, 0, 1, h), new Vector2(0.5f, 0.5f), 64f);
                _topGrad.name = "TopGradient";
                return _topGrad;
            }
        }

        /// A real-looking film/emulsion SCRATCH: a feathered hairline that WANDERS a little
        /// and breaks up along its length (noise-modulated, tapered ends) instead of a crisp
        /// solid stick. Vertical; stretch it to length and rotate slightly for film damage.
        static Sprite _scratch;
        public static Sprite FilmScratch
        {
            get
            {
                if (_scratch != null) return _scratch;
                int w = 10, h = 160;
                var tex = new Texture2D(w, h, TextureFormat.RGBA32, false)
                { filterMode = FilterMode.Bilinear, wrapMode = TextureWrapMode.Clamp };
                var px = new Color32[w * h];
                for (int y = 0; y < h; y++)
                {
                    float fy = y / (float)(h - 1);
                    float wander = (ValueNoise(0f, y / 24f, 3) - 0.5f) * 4f;            // slow ±2px meander
                    float cx = w * 0.5f + wander;
                    float taper = Mathf.SmoothStep(0f, 0.12f, fy) * (1f - Mathf.SmoothStep(0.86f, 1f, fy));
                    float vn = ValueNoise(0f, y / 7f, 11) * 0.6f + ValueNoise(0f, y / 2.5f, 23) * 0.4f;
                    float vmod = taper * Mathf.Clamp01(0.18f + 0.95f * vn);             // intermittent down the length
                    for (int x = 0; x < w; x++)
                    {
                        float d = Mathf.Abs(x - cx);
                        float core = Mathf.Clamp01(1f - d / 1.7f); core *= core;        // feathered ~1.7px half-width
                        px[y * w + x] = new Color32(255, 255, 255, (byte)(Mathf.Clamp01(core * vmod) * 255f));
                    }
                }
                tex.SetPixels32(px); tex.Apply();
                _scratch = Sprite.Create(tex, new Rect(0, 0, w, h), new Vector2(0.5f, 0.5f), 160f);
                _scratch.name = "FilmScratch";
                return _scratch;
            }
        }

        /// Soft lamp light cone (wide at the bottom, fading down).
        public static Sprite LightCone
        {
            get
            {
                if (_lightCone == null)
                {
                    int w = 96, h = 128;
                    var tex = new Texture2D(w, h, TextureFormat.RGBA32, false);
                    tex.filterMode = FilterMode.Bilinear;
                    var px = new Color32[w * h];
                    for (int y = 0; y < h; y++)
                        for (int x = 0; x < w; x++)
                        {
                            float v = 1f - y / (float)h;             // 0 top (at the lamp) -> 1 bottom
                            float halfW = Mathf.Lerp(0.10f, 0.48f, v) * w;
                            float dx = Mathf.Abs(x - w / 2f);
                            float a = dx < halfW
                                ? Mathf.Pow(1f - dx / halfW, 1.4f) * Mathf.Pow(1f - v, 1.6f) * 0.55f
                                : 0f;
                            px[y * w + x] = new Color32(255, 244, 222, (byte)(a * 255f));
                        }
                    // texture row 0 is the BOTTOM: invert so the cone widens downward
                    var flipped = new Color32[w * h];
                    for (int y = 0; y < h; y++)
                        for (int x = 0; x < w; x++)
                            flipped[y * w + x] = px[(h - 1 - y) * w + x];
                    tex.SetPixels32(flipped);
                    tex.Apply();
                    _lightCone = Sprite.Create(tex, new Rect(0, 0, w, h), new Vector2(0.5f, 1f), 32f, 0, SpriteMeshType.FullRect);
                    _lightCone.name = "LightCone";
                }
                return _lightCone;
            }
        }

        static Sprite _lightBeam;
        /// A single natural volumetric beam: HOT at the source (top), a brighter
        /// inner core, gaussian-feathered (soft, not a hard cone), gently widening,
        /// fading smoothly to nothing along its length. Pivot top-centre so it
        /// emanates from the bulb. Replaces the old hard double-cone.
        public static Sprite LightBeam
        {
            get
            {
                if (_lightBeam == null)
                {
                    int w = 128, h = 200;
                    var tex = new Texture2D(w, h, TextureFormat.RGBA32, false);
                    tex.filterMode = FilterMode.Bilinear;
                    var px = new Color32[w * h];
                    for (int y = 0; y < h; y++)
                        for (int x = 0; x < w; x++)
                        {
                            float ty = (h - 1 - y) / (float)(h - 1);              // 0 source (top) -> 1 far end
                            float halfW = Mathf.Lerp(0.07f, 0.40f, Mathf.Pow(ty, 0.8f)) * w;
                            float dx = Mathf.Abs(x - w / 2f) / halfW;
                            float soft = Mathf.Exp(-dx * dx * 2.1f);              // feathered body (no hard edge)
                            float core = Mathf.Exp(-dx * dx * 8.5f);              // tighter bright core streak
                            float vert = Mathf.Pow(1f - ty, 1.6f);               // fade down the length
                            float hot = Mathf.Exp(-ty * ty * 24f);               // bright hot-spot at the source
                            float a = (soft * 0.5f + core * 0.5f) * vert + hot * soft * 0.55f;
                            px[y * w + x] = new Color32(255, 244, 222, (byte)(Mathf.Clamp01(a) * 0.62f * 255f));
                        }
                    tex.SetPixels32(px);
                    tex.Apply();
                    _lightBeam = Sprite.Create(tex, new Rect(0, 0, w, h), new Vector2(0.5f, 1f), 44f, 0, SpriteMeshType.FullRect);
                    _lightBeam.name = "LightBeam";
                }
                return _lightBeam;
            }
        }

        static Sprite _edgeFade;
        /// Vertical gradient: opaque at the TOP, fading to transparent downward — a soft
        /// catch-light rim that bleeds a platform's lit lip down its face (a 3D-ledge cue).
        /// Pivot top-centre so it grows downward from the lip.
        public static Sprite EdgeFade
        {
            get
            {
                if (_edgeFade == null)
                {
                    // square + ppu==h so native size is exactly 1x1 world units (like
                    // WhiteSprite): a localScale of (s.x, rimH) then gives the right size.
                    // (An 8-wide texture at ppu 64 was only 0.125u native -> a thin streak.)
                    int w = 64, h = 64;
                    var tex = new Texture2D(w, h, TextureFormat.RGBA32, false);
                    tex.filterMode = FilterMode.Bilinear;
                    var px = new Color32[w * h];
                    for (int y = 0; y < h; y++)
                        for (int x = 0; x < w; x++)
                        {
                            float ty = (h - 1 - y) / (float)(h - 1);   // 0 top -> 1 bottom
                            float a = Mathf.Pow(1f - ty, 2.2f);
                            px[y * w + x] = new Color32(255, 255, 255, (byte)(a * 255f));
                        }
                    tex.SetPixels32(px);
                    tex.Apply();
                    _edgeFade = Sprite.Create(tex, new Rect(0, 0, w, h), new Vector2(0.5f, 1f), h, 0, SpriteMeshType.FullRect);
                    _edgeFade.name = "EdgeFade";
                }
                return _edgeFade;
            }
        }

        /// Hanging lamp shade silhouette (truncated cone).
        public static Sprite ConeShade
        {
            get
            {
                if (_coneShade == null)
                {
                    int w = 48, h = 28;
                    var tex = new Texture2D(w, h, TextureFormat.RGBA32, false);
                    tex.filterMode = FilterMode.Bilinear;
                    var px = new Color32[w * h];
                    for (int y = 0; y < h; y++)
                        for (int x = 0; x < w; x++)
                        {
                            float v = y / (float)h;                  // 0 bottom -> 1 top
                            float halfW = Mathf.Lerp(0.48f, 0.10f, v) * w;
                            float dx = Mathf.Abs(x - w / 2f);
                            bool inside = dx < halfW;
                            byte g = (byte)(inside ? (y < 3 ? 0x2E : 0x17) : 0);
                            px[y * w + x] = new Color32(g, g, (byte)(g + 2), (byte)(inside ? 255 : 0));
                        }
                    tex.SetPixels32(px);
                    tex.Apply();
                    _coneShade = Sprite.Create(tex, new Rect(0, 0, w, h), new Vector2(0.5f, 0f), 48f, 0, SpriteMeshType.FullRect);
                    _coneShade.name = "ConeShade";
                }
                return _coneShade;
            }
        }

        /// Stone blocks: grout lines + deterministic speckle.
        public static Sprite GroundTile
        {
            get
            {
                if (_ground == null)
                    _ground = MakeTile("GroundTile", 16, 16f, (x, y) =>
                    {
                        if (x == 0 || y == 0) return C(0x5F5F5F);
                        int n = (x * 7 + y * 13) % 7;
                        if (n == 0) return C(0x676767);
                        if (n == 3) return C(0x747474);
                        return C(0x6E6E6E);
                    });
                return _ground;
            }
        }

        /// Glowing cold-blue energy band: bright core line, soft vertical
        /// falloff. Drawn stretched (not tiled) — it is a gradient.
        public static Sprite DarkPathTile
        {
            get
            {
                if (_darkPath == null)
                {
                    int w = 16, h = 64;
                    var tex = new Texture2D(w, h, TextureFormat.RGBA32, false);
                    tex.filterMode = FilterMode.Bilinear;
                    tex.wrapMode = TextureWrapMode.Repeat;
                    var px = new Color32[w * h];
                    for (int y = 0; y < h; y++)
                        for (int x = 0; x < w; x++)
                        {
                            float dy = Mathf.Abs(y - h / 2f) / (h / 2f);
                            float core = Mathf.Pow(Mathf.Max(0f, 1f - dy), 2.4f);
                            var col = Color.Lerp(new Color(0.34f, 0.45f, 0.85f), new Color(0.86f, 0.92f, 1f), core);
                            px[y * w + x] = new Color32(
                                (byte)(col.r * 255f), (byte)(col.g * 255f), (byte)(col.b * 255f),
                                (byte)(Mathf.Clamp01(0.25f + core * 0.75f) * 255f));
                        }
                    tex.SetPixels32(px);
                    tex.Apply();
                    _darkPath = Sprite.Create(tex, new Rect(0, 0, w, h), new Vector2(0.5f, 0.5f), h, 0, SpriteMeshType.FullRect);
                    _darkPath.name = "DarkPathBand";
                }
                return _darkPath;
            }
        }

        /// Pale fog-glass panel: translucent vertical sheen (cinematic restyle).
        public static Sprite BarrierTile
        {
            get
            {
                if (_barrier == null)
                    _barrier = MakeTile("BarrierTile", 32, 32f, (x, y) =>
                    {
                        float sheen = 0.5f + 0.5f * Mathf.Sin(x * 0.7f);
                        float n = ValueNoise(x / 6f, y / 6f, 71);
                        byte a = (byte)(Mathf.Clamp01(0.72f + sheen * 0.18f + n * 0.08f) * 255f);
                        return new Color32(0xE9, 0xE9, 0xE6, a);
                    });
                return _barrier;
            }
        }

        /// Horizontal slats.
        public static Sprite DoorTile
        {
            get
            {
                if (_door == null)
                    _door = MakeTile("DoorTile", 48, 48f, (x, y) =>
                    {
                        if (y % 16 < 2) return C(0x4F4F4F);   // recessed slat shadow
                        if (x < 2) return C(0x575757);        // side bevel
                        return C(0x5E5E5E);
                    });
                return _door;
            }
        }

